var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"예? 델타세븐이라면......","JPN":"はい？　デルタセブンなら……","ENG":"Pardon? Delta Seven is...","TWN":"嗯？第七三角洲部隊……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"그래, 네가 존경해 마지 않는 마리아 안토노프 사령관님께서 지휘하는 부대다.","JPN":"そうだ、君が尊敬してやまないマリア・アントノフ司令官が率いる部隊だ。","ENG":"That's right. It's the unit under the command of your favorite Maria Antonov.","TWN":"沒錯，就是你無比尊敬的那位瑪麗亞·安東諾夫司令官所指揮的部隊。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"화려한 근접 전투 시연을 하라고 보내놨더니 20초 만에 행사를 끝내버려서 한 소리 듣겠다 싶었는데......","JPN":"華やかな近接戦闘試演を披露するようと言ったはずだが、たった20秒でイベントを終わらせてしまい、\\n詰問されるんじゃないかと思ったが……","ENG":"You were supposed to make the demonstration all fancy, but you finished it in 20 seconds. I was sure you'd be getting a mouthful for that...","TWN":"本來想讓你來一場精彩的近戰表演，結果戰鬥20秒就結束了，還以為她會抱怨幾句呢……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"다행히 좋게 봐주신 모양이더군.","JPN":"幸いにも高く評価してくださったようだ。","ENG":"But fortunately for you, I guess the top brass took kindly to your antics.","TWN":"幸好她似乎很滿意。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"넌 이제부터 델타세븐 내사과 소속의 카일 웡 대위가 되는 거야.","JPN":"君はこれからデルタセブン内偵課所属のカイル・ウォン大尉になるんだ。","ENG":"From now on, you'll be Captain Kyle Wong of the Internal Investigation Department of Delta Seven.","TWN":"從現在起，你就是第七三角洲部隊內務科的一員了，凱爾大尉。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그게 정말입니까?","JPN":"それは本当ですか？","ENG":"Could this really be true?","TWN":"真的嗎？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제가 델타세븐 소속......","JPN":"僕がデルタセブン所属……","ENG":"Me? Delta Seven?","TWN":"要我加入第七三角洲部隊……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"결재에 착오가 있을 지도 모릅니다.","JPN":"決裁に間違いがあったのかもしれません｡","ENG":"There may have been an error with the paperwork.","TWN":"說不定這個決策是錯誤的。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"만일을 대비해 당사자의 입장에서 진위 여부에 대한 사실확인 절차가 필요할 것 같습니다만.","JPN":"万が一のために、当事者の立場で真偽の程について事実確認の手続きが必要だと思いますが。","ENG":"Just to be safe, I think this may warrant a verification of the respective documentation by the parties affected.","TWN":"以防萬一，我必須以當事人的立場確認事情的真偽。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"나 참. 발령서 보여달란 얘기를 뭘 그렇게 어렵게 해?","JPN":"やれやれ。命令書を見たいという話をそんなに難しくするのか？","ENG":"Geez. That's a long-winded way to say you want to see your orders.","TWN":"真是的。命令書就這麼寫的，為什麼你要搞得這麼複雜？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"자, 여기. 실컷 읽어봐라.","JPN":"ほら、これだ。好きなだけ読んでみろ。","ENG":"Here you go. Read it all you'd like.","TWN":"來，就在這裡，自己好好看看吧。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이건 분명 국방부 직인이 찍힌 명령서...... 틀림없군요.","JPN":"これは確かに国防省の公印が押された命令書……間違いありませんね。","ENG":"This is indeed a personnel action order with the official stamp of the Department of Defense... There's no question about it.","TWN":"這確實是國防部蓋章的命令書……沒有問題。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"그래. 훈련병 주제에 대위 진급이라는 전례 없는 특혜다.","JPN":"そうだ。訓練兵から大尉への進級は、前例のない特別な措置だ。","ENG":"That's right. You're going from a trainee straight to Captain. I've never seen anyone get this kind of special treatment.","TWN":"對，一個訓練兵居然直接晉升為大尉，這可是特別待遇。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"그러니 트집 잡히기 싫으면 우쭐해 하지 말고 처신 잘 해야 할 거야.","JPN":"言いがかりをつけられなくなかったら、調子に乗らずに立ち振る舞いに気をつけろ。","ENG":"So you'd better carry yourself well. Don't get cocky, or others might look for a way to bring you down.","TWN":"如果你不想被抓到把柄就低調一點。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"뭐, 계급은 고사하고 델타세븐에 불려간다는 것 자체가 그리 좋은 일은 아닌 것 같다만......","JPN":"まぁ、階級はさておき、デルタセブンに異動になったこと自体があまり良くないことだろうが……","ENG":"Then again, I guess getting dragged to Delta Seven's not exactly something to celebrate...","TWN":"不過，先不說什麼晉升的事，光是被第七三角洲部隊叫過去就肯定不是什麼好事……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"교관 중위. 말하는 중에 미안하지만, 여긴 군대입니다. 상관인 제게 하대는 지양해주시죠.","JPN":"教官中尉。お話し中すみませんが、ここは軍です。上官である僕をぞんざいに扱うことはご遠慮願います。","ENG":"Instructor Lieutenant. I'd hate to interrupt you, but this is the military. I advise you refrain from treating your superior like a subordinate.","TWN":"教官中尉。很抱歉打斷您，但這裡是軍隊。長官對下屬的命令是絕對的。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TRAINER_NPC_NULL_NULL","text":{"KOREA":"야, 이 자식아. 너 아직 진급식도 안 했거든?","JPN":"おい、こら。まだ進級申告式もやってないぞ。","ENG":"Hey, you little brat. You haven't even had your promotion ceremony yet, alright?","TWN":"喂，你這傢伙，你知不知道你還沒參加晉升儀式？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"진급 신고는 의례적인 절차일 뿐입니다. 이 서류를 통해 이미 실효성이 발휘된 상태니까요.","JPN":"進級申告式は形式的手続きに過ぎません。この書類ですでに実効性が発揮された状態ですから。","ENG":"A ceremony is merely that. A ceremony. With this document, my new rank has already entered into force.","TWN":"晉升儀式不過是走走程序罷了。我收到這份文件的這一刻，命令就已經生效了。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};